import { useState } from "react";
import Logo from "../components/Logo";
import { BG_IMAGE, glowStyles } from "./GlowAndShine.styles";

export default function GlowAndShine({ onExplore, onLogin, onSignup }) {
  const [hovered, setHovered] = useState(null);

  return (
    <div style={{ position: "relative", width: "100%", minHeight: "100vh", overflow: "hidden", fontFamily: "'Libre Bodoni', serif" }}>
      <style>{glowStyles}</style>
      <img src={BG_IMAGE} alt="Glow & Shine background" style={{ position: "absolute", inset: 0, width: "100%", height: "100%", objectFit: "cover", pointerEvents: "none" }} />
      <div style={{ position: "absolute", top: 16, left: 24 }} className="fade-up-1">
        <Logo size={100} />
      </div>
      <div className="nav-buttons" style={{ position: "absolute", top: 24, right: 24, display: "flex", gap: 16 }}>
        <button className="btn nav-btn fade-up-1" style={{ width: 205, height: 35, fontSize: 24 }} onClick={onLogin}>Log in</button>
        <button className="btn nav-btn fade-up-1" style={{ width: 205, height: 35, fontSize: 24 }} onClick={onSignup}>Sign up</button>
      </div>
      <div className="glass-card" style={{ position: "absolute", top: 115, left: "calc(50% - 346px)", width: 693, height: 694, borderRadius: 105, background: "rgba(250, 243, 232, 0.40)", backdropFilter: "blur(10px)", WebkitBackdropFilter: "blur(10px)", boxShadow: "0 4px 4px rgba(0,0,0,0.25)", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 0, padding: "56px 40px", textAlign: "center" }}>
        <h1 className="title fade-up-2" style={{ fontSize: 64, fontWeight: 400, color: "#000", lineHeight: "normal", marginBottom: 48 }}>Glow &amp; Shine</h1>
        <h2 className="subtitle fade-up-3" style={{ fontSize: 24, fontWeight: 700, color: "#000", lineHeight: "normal", marginBottom: 40 }}>Timeless Beauty, Modern Touch</h2>
        <p className="body-text fade-up-3" style={{ fontSize: 24, fontWeight: 700, color: "#000", lineHeight: 1.45, marginBottom: 60 }}>
          Discover premium beauty services,<br />explore trusted professionals<br />and book appointments in just a few clicks.
        </p>
        <button className="btn cta-btn fade-up-4" style={{ width: 293, height: 45, fontSize: 24 }} onClick={onExplore}>Explore our website!</button>
      </div>
    </div>
  );
}
